/* =============================================================
   /flow3 — Mismo motor de transiciones que /flow2 (Framework7 con la
   View Transitions API), pero cada PÁGINA declara su propia transición.
   Copia independiente para no acoplar /flow3 a /flow2.
   =============================================================

   Mapeo a View Transitions (el panel lleva view-transition-name: content):
     - ::view-transition-old(content) === página saliente
     - ::view-transition-new(content) === página entrante
   Cada transición usa keyframes distintos según la dirección forward/backward.
   ============================================================= */

:root {
	--flow3-void: oklch(0.97 0 0);
}
html.dark {
	--flow3-void: oklch(0.145 0 0);
}

/* Root ESTÁTICO en /flow3: sólo anima el panel `content`. */
html.flow3-active::view-transition-old(root),
html.flow3-active::view-transition-new(root) {
	animation: none;
}

/* El panel se recorta a su caja y usa fondo sólido para rellenar zonas que se
   revelan durante el movimiento. */
::view-transition-group(content) {
	overflow: clip;
	background-color: var(--card);
	border-radius: calc(var(--radius) - 2px);
}

html.cover::view-transition-group(content),
html.cover-v::view-transition-group(content),
html.flip::view-transition-group(content) {
	background-color: var(--flow3-void);
}

::view-transition-old(content),
::view-transition-new(content) {
	animation-fill-mode: both;
	height: 100%;
	width: 100%;
	transform-origin: center;
}
::view-transition-old(content) {
	z-index: 1;
}
::view-transition-new(content) {
	z-index: 2;
}

html.cover::view-transition-image-pair(content),
html.cover-v::view-transition-image-pair(content),
html.dive::view-transition-image-pair(content),
html.flip::view-transition-image-pair(content) {
	perspective: 1200px;
}

/* Backward de cover/cover-v/parallax/circle: la saliente va ENCIMA. */
html.cover.backward::view-transition-old(content),
html.cover-v.backward::view-transition-old(content),
html.parallax.backward::view-transition-old(content),
html.circle.backward::view-transition-old(content) {
	z-index: 2;
}
html.cover.backward::view-transition-new(content),
html.cover-v.backward::view-transition-new(content),
html.parallax.backward::view-transition-new(content),
html.circle.backward::view-transition-new(content) {
	z-index: 1;
}

/* ===================== FADE ===================== */
html.fade::view-transition-old(content) {
	animation: f7-fade-out 500ms ease-in-out both;
}
html.fade::view-transition-new(content) {
	animation: f7-fade-in 500ms ease-in-out both;
}
@keyframes f7-fade-out {
	from {
		opacity: 1;
	}
	to {
		opacity: 0;
	}
}
@keyframes f7-fade-in {
	from {
		opacity: 0;
	}
	to {
		opacity: 1;
	}
}

/* ===================== PUSH ===================== */
html.push.forward::view-transition-old(content) {
	animation: f7-push-current-to-prev 400ms both;
}
html.push.forward::view-transition-new(content) {
	animation: f7-push-next-to-current 400ms both;
}
html.push.backward::view-transition-old(content) {
	animation: f7-push-current-to-next 400ms both;
}
html.push.backward::view-transition-new(content) {
	animation: f7-push-prev-to-current 400ms both;
}
@keyframes f7-push-next-to-current {
	from {
		transform: translateX(100%);
	}
	to {
		transform: translateX(0%);
	}
}
@keyframes f7-push-current-to-next {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(100%);
	}
}
@keyframes f7-push-current-to-prev {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(-100%);
	}
}
@keyframes f7-push-prev-to-current {
	from {
		transform: translateX(-100%);
	}
	to {
		transform: translateX(0%);
	}
}

/* ===================== PARALLAX ===================== */
html.parallax.forward::view-transition-old(content) {
	animation: f7-parallax-current-to-prev 450ms both;
}
html.parallax.forward::view-transition-new(content) {
	animation: f7-parallax-next-to-current 450ms both;
}
html.parallax.backward::view-transition-old(content) {
	animation: f7-parallax-current-to-next 450ms both;
}
html.parallax.backward::view-transition-new(content) {
	animation: f7-parallax-prev-to-current 450ms both;
