	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(100%);
	}
}
@keyframes f7-parallax-current-to-prev {
	from {
		transform: translateX(0%);
		opacity: 1;
	}
	to {
		transform: translateX(-20%);
		opacity: 0.3;
	}
}
@keyframes f7-parallax-prev-to-current {
	from {
		transform: translateX(-20%);
		opacity: 0.3;
	}
	to {
		transform: translateX(0%);
		opacity: 1;
	}
}

/* ===================== COVER ===================== */
html.cover.forward::view-transition-old(content) {
	animation: f7-cover-current-to-prev 450ms both;
}
html.cover.forward::view-transition-new(content) {
	animation: f7-cover-next-to-current 450ms both;
